  ('elementary-10ced7e2-moex-00636', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '以下何種權利屬於智慧財產權？', '["債權", "抵押權", "商標權", "姓名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00637', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '甲基金會自創辦以來，致力於雛妓救援與家暴受害者庇護，近年尤努力消彌社會中所有性/性別暴力行為 與壓迫，以建立性別公義的社會。有關甲基金會的敘述，下列何者正確？', '["和政黨一樣都是屬於非營利組織", "從民法的屬性分類屬於社團法人", "關心社會議題的層面較政黨多元", "常藉由政治參選達成該組織宗旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00638', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
