  ('elementary-10ced7e2-moex-00640', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '某甲認為年輕人自己不夠努力因此才買不起房子，某乙反駁認為，許多財團手握大筆資金投入房地產市 場，成為炒房元兇，年輕人靠著微薄的薪水，不論如何努力也永遠追不上高漲的房價。某乙的說法最接 近下列何項觀點？', '["功能論", "衝突論", "成就地位論", "人力資本論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
